  const orderId = item.json.orderId;

  // 根据orderId返回不同的响应
  if (orderId === 'E20251213141351044706185') {
    // 匹配第一个orderId，返回成功响应
    item.json = {
      "trace_id": "yz7-0a34f812-1766973335936-225786",
      "code": 200,
      "data": {
        "is_success": true,
        "refund_id": "202512290955350020200447"
      },
      "success": true,
      "message": "successful"
    };
  } else if (orderId === 'E20230526153831018600079') {
    // 匹配第二个orderId，返回失败响应
    item.json = {
      "trace_id": "yz7-0a34f81f-1766973335928-336094",
      "code": 1020000013,
      "success": false,
      "message": "订单退款时间超过渠道时间限制"
    };
  } 
  else if (orderId === 'E20230526153831018600080') {
    // 匹配第二个orderId，返回失败响应
    item.json = {
      "trace_id": "yz7-0a34f81f-1766973335928-336095",
      "code": 1020000013,
      "success": false,
      "message": "订单退款时间超过渠道时间限制"
    };
  } 
  else {
    // 可选：处理其他未匹配的orderId情况（可根据需求修改）
    item.json = {
      "trace_id": "unknown",
      "code": 404,
      "success": false,
      "message": "订单ID未匹配"
    };
  }
}

// 输出处理后的items
return $input.all();

// 1. 获取Loop Over Items节点的数据
const requestData = $('Loop Over Items').first().json;
// 2. 获取上一个节点的响应结果（接口返回数据）
const responseData = $input.first().json;
// 3. 深度合并请求参数和响应结果（避免嵌套对象丢失）
const mergedData = {
  ...requestData,  // 原始请求参数（orderId、Matnr等）
  ...responseData  // 接口响应结果（trace_id、code等）
};

// 4. 输出拼接后的item，保持n8n标准格式
return [
  {
    json: mergedData
  }
];

// 从n8n的输入数据中获取上一个节点的输出
const inputData = $input.all();

// 用于存储提取出的refund_id
const result = [];

// 遍历所有输入项
for (const item of inputData) {
  // 检查当前项的code是否为200
  if (item.json.code === 200) {
    // 提取refund_id并添加到结果数组中
    const refundId = item.json.data?.refund_id;
    if (refundId) {
      result.push({
        json: {
          trace_id: item.json.trace_id, // 保留trace_id便于溯源
          refund_id: refundId
        }
      });
    }
  }
}

// 将结果输出到下一个节点
return result;

// 1. 获取所有输入的item
const inputItems = $input.all();

// 2. 遍历处理每个item，生成successList的子项
const successList = inputItems.map(item => {
  // 提取当前item的核心数据
  const data = item.json;

  // 确定退款金额和提示语：成功则取total_price，失败则为0；提示语适配场景
  const refund_price = data.success ? data.total_price : 0;
  const message = data.success ? "退款成功" : data.message;

  // 返回格式化后的子项
  return {
    orderId: data.orderId,
    Matnr: data.Matnr,
    total_price: data.total_price,
    oid: data.oid,
    refund_price: refund_price,
    message: message
  };
});

// 3. 按要求格式输出（外层是包含successList的单个item）
return [
  {
    json: {
      successList: successList
    }
  }
];

// 1. 获取所有输入的item
const inputItems = $input.all();

// 2. 提取所有退款失败的orderId，并存入Set自动去重
const failedOrderIds = new Set();
inputItems.forEach(item => {
  const data = item.json;
  // 仅筛选success为false的订单，且确保orderId存在
  if (data.success === false && data.orderId) {
    failedOrderIds.add(data.orderId);
  }
});

// 3. 将去重后的订单ID拼接为字符串（逗号分隔）
const errMsg = Array.from(failedOrderIds).join(",");

// 4. 按要求格式输出（单个item包含errMsg字段）
return [
  {
    json: {
      errMsg: errMsg
    }
  }
];
